
(function () {
    'use strict';

    const SERVER_URL = 'https://scholarship.wenzhub.top';
    // const protectedVipData = '...'; // loaded by other js 
    let enhance_mode = false; // Default value, will be updated from storage.
    let currentIFRange = null; // Default to null, will be set by slider
    let currentZKYfilters = new Set(); // An empty set means show all
    let isGSProcessing = false;

    async function fetchAndCache(url, storageKey, isJson = false) {
        const cachedData = await new Promise(resolve => chrome.storage.local.get(storageKey, result => resolve(result[storageKey])));
        if (cachedData) {
            return cachedData;
        }
        const response = await fetch(url);
        if (!response.ok) {
            throw new Error(`Failed to fetch ${url}: ${response.statusText}`);
        }
        const data = isJson ? await response.json() : await response.text();
        chrome.storage.local.set({ [storageKey]: data });
        return data;
    }

    async function loadData(SECRET_KEY, customKey = 'general') {
        const protectedVipData = await fetchAndCache(`${SERVER_URL}/data/${customKey}_data`, `cachedJcrData_${customKey}`);

        let jcrCsvText;
        try {
            const bytes = CryptoJS.AES.decrypt(protectedVipData, SECRET_KEY);
            jcrCsvText = bytes.toString(CryptoJS.enc.Utf8);

            if (!jcrCsvText) {
                throw new Error("decode error");
            }
        } catch (error) {
            console.error("decode error", error);
            return Promise.resolve([]);
        }
        return new Promise(resolve => {
            Papa.parse(jcrCsvText, {
                header: true,
                skipEmptyLines: true,
                complete: results => resolve(results.data)
            });
        });
    }
    function normalizeName(text) {
        return text
            ? text.replace(/[:.,\-]/g, ' ')
                .replace(/\s+/g, ' ')
                .trim()
                .toLowerCase()
            : '';
    }

    function normalizeWords(text) {
        const stopwords = new Set(['on', 'the', 'and', 'of', 'a', 'an', '&']);
        return text
            ? (text.match(/[a-z]+/gi) || [])
                .map(w => w.toLowerCase())
                .filter(w => !stopwords.has(w))
            : [];
    }

    function nameToWordSet(name) {
        return new Set(normalizeWords(name));
    }

    function setSimilarity(setA, setB) {
        if (setA.size === 0 || setB.size === 0) return 0;

        const [smallerSet, largerSet] = (setA.size < setB.size) ? [setA, setB] : [setB, setA];
        const largerSetArray = Array.from(largerSet);
        let matchCount = 0;

        smallerSet.forEach(sWord => {
            for (let i = 0; i < largerSetArray.length; i++) {
                const lWord = largerSetArray[i];
                if (!lWord) continue;
                const isPrefix = lWord.startsWith(sWord) || sWord.startsWith(lWord);

                if (isPrefix) {
                    matchCount++;
                    largerSetArray[i] = null;
                    break;
                }
            }
        });

        const unionSize = setA.size + setB.size - matchCount;
        if (unionSize === 0) return 1;

        return matchCount / unionSize;
    }

    function findJournalEntry(journalNameText, jcrData) {
        const normJournalName = normalizeName(journalNameText);
        const normWordSet = nameToWordSet(journalNameText);

        let jcrEntry = jcrData.find(row => {
            if (!row.name) return false;
            return normalizeName(row.name) === normJournalName;
        });

        if (!jcrEntry) {
            const bestMatch = jcrData.reduce(
                (highestFound, currentRow) => {
                    if (!currentRow._wordSet) return highestFound;
                    const currentScore = setSimilarity(normWordSet, currentRow._wordSet);
                    if (currentScore > highestFound.score) {
                        return { score: currentScore, row: currentRow };
                    }
                    return highestFound;
                },
                { score: -1, row: null }
            );
            if (bestMatch.row && bestMatch.score > 1.0 - 0.08 * bestMatch.row._wordSet.size) {
                jcrEntry = bestMatch.row;
            }
        }
        return jcrEntry;
    }

    function generateInfoHTML(jcrEntry) {
        let tempInfoHtml = '';
        if (jcrEntry) {
            tempInfoHtml += `<span style="background-color:#722ed1;color:white;padding:2px 3px;border-radius:3px;">IF ${jcrEntry.if || 'N/A'}</span> `;
            tempInfoHtml += `<span style="background-color:#00868f;color:white;padding:2px 3px;border-radius:3px;">${jcrEntry.jcr || 'N/A'}</span> `;
            tempInfoHtml += `<span style="background-color:#08979c;color:white;padding:2px 3px;border-radius:3px;">${jcrEntry.class || 'N/A'}</span> `;
            if (enhance_mode && jcrEntry.zkyfq) {
                tempInfoHtml += `<span style="background-color:#1677ff;color:white;padding:2px 3px;border-radius:3px;">中科院${jcrEntry.zkyfq || 'N/A'}区</span> `;
                tempInfoHtml += `<span style="background-color:#096dd9;color:white;padding:2px 3px;border-radius:3px;">同类排名 ${jcrEntry.rank || 'N/A'}</span> `;
                tempInfoHtml += jcrEntry.isTop == 'True' ? `<span style="background-color:#fa8c16;color:white;padding:2px 3px;border-radius:3px;">Top</span> ` : '';
                tempInfoHtml += jcrEntry.onHold == 'True' ? `<span style="background-color:#f5222d;color:white;padding:2px 3px;border-radius:3px;">On Hold</span> ` : '';
                tempInfoHtml += `<span style="background-color:#f5f5f5;color:#262626;padding:2px 3px;border-radius:3px;">EISSN: ${jcrEntry.eissn || 'N/A'}</span> <br/>`;
                tempInfoHtml += `<span style="background-color:#FFDEAD;color:#262626;padding:2px 3px;border-radius:3px;">大类 ${jcrEntry.domain || 'N/A'}区</span> `;
                for (const subd of jcrEntry.subdomain.split(';')) {
                    tempInfoHtml += `<span style="background-color:#FFF8DC;color:#262626;padding:2px 3px;border-radius:3px;">小类 ${subd || 'N/A'}区</span> <br/>`;
                }
            } else {
                tempInfoHtml += ` <span style="background-color:#f5f5f5;color:#262626;padding:2px 3px;border-radius:3px;">EISSN: ${jcrEntry.eissn || 'N/A'}</span> `;
                tempInfoHtml += `<span style="padding:2px 3px;border-radius:3px;"><a href="${SERVER_URL}" style="color:#d48806; text-decoration: none;">Plus</a></span> `;
            }
        }
        else {
            tempInfoHtml += `<span style="background-color:#FFF8DC; color:#262626;padding:2px 3px;border-radius:3px;"> <a href="${SERVER_URL}" style="color:#262626; text-decoration: none;">无匹配期刊/No Data Found</a></span>`;
        }

        const parts = tempInfoHtml.split('<br/>').filter(part => part.trim() !== '');
        if (parts.length > 1) {
            let infoHtml = `<div>${parts[0]}</div>`;
            for (let i = 1; i < parts.length; i++) {
                infoHtml += `<div style="margin-top:5px">${parts[i]}</div>`;
            }
            return infoHtml;
        }
        return tempInfoHtml;
    }

    function applyFilters() {
        document.querySelectorAll('article.full-docsum').forEach(article => {
            const infoAddon = article.querySelector('.journal-info-addon');
            let ifValue = null;
            let zkyValue = null;
            let isTop = false;

            if (infoAddon) {
                const ifSpan = infoAddon.querySelector('span:first-child');
                if (ifSpan && ifSpan.textContent.startsWith('IF')) {
                    const ifText = ifSpan.textContent.replace('IF', '').trim();
                    if (ifText !== 'N/A') {
                        ifValue = parseFloat(ifText);
                    }
                }

                if (enhance_mode) {
                    const spans = infoAddon.querySelectorAll('span');
                    spans.forEach(span => {
                        if (span.textContent.startsWith('中科院')) {
                            const zkyText = span.textContent.replace('中科院', '').replace('区', '').trim();
                            if (zkyText !== 'N/A') {
                                zkyValue = zkyText;
                            }
                        }
                        if (span.textContent === 'Top') {
                            isTop = true;
                        }
                    });
                }
            }

            let shouldShowIF = false;
            if (currentIFRange === null) {
                shouldShowIF = true;
            } else {
                const sliderElem = document.getElementById('if-slider');
                if (!sliderElem || !sliderElem.noUiSlider) {
                    shouldShowIF = true;
                } else {
                    const sliderRange = sliderElem.noUiSlider.options.range;
                    const minRange = parseFloat(sliderRange.min);
                    const maxRange = parseFloat(sliderRange.max);

                    // Show all (including N/A) if slider is at its absolute max range
                    if (currentIFRange[0] === minRange && currentIFRange[1] === maxRange) {
                        shouldShowIF = true;
                    } else {
                        shouldShowIF = ifValue !== null && ifValue >= currentIFRange[0];
                        if (currentIFRange[1] < maxRange) { shouldShowIF = shouldShowIF && ifValue <= currentIFRange[1] }
                    }
                }
            }

            let shouldShowZKY = true;
            if (enhance_mode) {
                const zkyPartitionFilters = new Set([...currentZKYfilters].filter(f => f !== 'top'));
                const topFilterIsSelected = currentZKYfilters.has('top');

                if (currentZKYfilters.size === 0) {
                    shouldShowZKY = true;
                } else {
                    const passZkyPartitionFilter = (zkyPartitionFilters.size === 0) || (zkyValue && zkyPartitionFilters.has(zkyValue));
                    const passTopFilter = !topFilterIsSelected || isTop;
                    shouldShowZKY = passZkyPartitionFilter && passTopFilter;
                }
            }

            article.style.display = (shouldShowIF && shouldShowZKY) ? '' : 'none';
        });
    }

    function createFilters() {
        const dateSearchFilter = document.querySelector('.choice-group.datesearch');
        if (!dateSearchFilter || document.getElementById('filter-container')) return;

        let minIF = Infinity;
        let maxIF = -Infinity;
        document.querySelectorAll('article.full-docsum').forEach(article => {
            const infoAddon = article.querySelector('.journal-info-addon');
            if (infoAddon) {
                const ifSpan = infoAddon.querySelector('span:first-child');
                if (ifSpan && ifSpan.textContent.startsWith('IF')) {
                    const ifText = ifSpan.textContent.replace('IF', '').trim();
                    if (ifText !== 'N/A') {
                        const ifValue = parseFloat(ifText);
                        if (ifValue < minIF) minIF = ifValue;
                        if (ifValue > maxIF) maxIF = ifValue;
                    }
                }
            }
        });

        if (minIF === Infinity || maxIF === -Infinity) {
            minIF = 0;
            maxIF = 300;
        } else if (minIF === maxIF) {
            minIF = Math.max(0, Math.floor(minIF - 5));
            maxIF = Math.ceil(maxIF + 5);
        } else {
            minIF = Math.floor(minIF);
            maxIF = Math.ceil(maxIF);
        }

        const filterContainer = document.createElement('div');
        filterContainer.id = 'filter-container';
        filterContainer.className = 'choice-group';
        filterContainer.innerHTML = `
            <h3 class="title">IF Filter</h3>
            <div class="timeline-filter side-timeline-filter lots-of-bars" style="">
                <div class="inner-wrap">
                    <div id="if-slider" class="slider"></div>
                </div>
            </div>
            ${enhance_mode ? `
            <h3 class="title" style="margin-top: 10px;">中科院分区</h3>
            <ul class="attributes-list choices-list" style="list-style: none; padding-left: 0;">
                <li><input type="checkbox" name="zky-filter-group" id="zky-filter-1" data-filter="1"><label for="zky-filter-1">中科院1区</label></li>
                <li><input type="checkbox" name="zky-filter-group" id="zky-filter-2" data-filter="2"><label for="zky-filter-2">中科院2区</label></li>
                <li><input type="checkbox" name="zky-filter-group" id="zky-filter-3" data-filter="3"><label for="zky-filter-3">中科院3区</label></li>
                <li><input type="checkbox" name="zky-filter-group" id="zky-filter-4" data-filter="4"><label for="zky-filter-4">中科院4区</label></li>
                <li><input type="checkbox" name="zky-filter-group" id="zky-filter-top" data-filter="top"><label for="zky-filter-top">Top期刊</label></li>
            </ul>
            ` : ''}
        `;

        dateSearchFilter.parentNode.insertBefore(filterContainer, dateSearchFilter);

        const slider = document.getElementById('if-slider');
        const sliderRange = {
            'min': minIF
        };
        if (maxIF > 20 && minIF < 10) {
            sliderRange['50%'] = 10;
            sliderRange['80%'] = 20;
            sliderRange['max'] = maxIF;
        } else if (maxIF > 20 && minIF < 20) {
            sliderRange['80%'] = 20;
            sliderRange['max'] = maxIF;
        } else {
            sliderRange['max'] = maxIF;
        }

        noUiSlider.create(slider, {
            start: [minIF, maxIF],
            connect: true,
            range: sliderRange,
            tooltips: [
                { to: value => value.toFixed(1) },
                { to: value => (value == maxIF) ? '+∞' : value.toFixed(1) }
            ]
        });

        currentIFRange = [minIF, maxIF];

        slider.noUiSlider.on('update', function (values, handle) {
            const [min, max] = values.map(v => parseFloat(v));
            currentIFRange = [min, max];
            applyFilters();
        });

        if (enhance_mode) {
            filterContainer.addEventListener('change', e => {
                const target = e.target;
                if (target.type === 'checkbox' && target.name === 'zky-filter-group') {
                    if (target.checked) {
                        currentZKYfilters.add(target.dataset.filter);
                    } else {
                        currentZKYfilters.delete(target.dataset.filter);
                    }
                    applyFilters();
                }
            });
        }
    }

    function insertLoadingPlaceholders() {
        const loadingHTML = `<span style="background-color:#f0f0f0;color:#999;padding:2px 3px;border-radius:3px;">Loading Data...</span>`;

        // PubMed Search Results
        document.querySelectorAll('article.full-docsum').forEach(article => {
            if (article.querySelector('.journal-info-addon') || article.querySelector('.journal-info-placeholder')) return;
            const citationElement = article.querySelector('.docsum-journal-citation');
            if (citationElement) {
                const placeholderDiv = document.createElement('div');
                placeholderDiv.className = 'journal-info-placeholder';
                placeholderDiv.style.marginTop = '5px';
                placeholderDiv.innerHTML = loadingHTML;
                citationElement.parentNode.insertBefore(placeholderDiv, citationElement.nextSibling);
            }
        });

        // PubMed Detail Page
        const pubmedDetailPageNode = document.querySelector('.full-view .article-source');
        if (pubmedDetailPageNode && !document.querySelector('.journal-info-addon-detail') && !document.querySelector('.journal-info-placeholder-detail')) {
            const placeholderDiv = document.createElement('div');
            placeholderDiv.className = 'journal-info-placeholder-detail';
            placeholderDiv.style.marginTop = '10px';
            placeholderDiv.style.marginBottom = '10px';
            placeholderDiv.innerHTML = loadingHTML;
            pubmedDetailPageNode.parentNode.insertBefore(placeholderDiv, pubmedDetailPageNode.nextSibling);
        }

        // PMC Detail Page
        const pmcDetailPageNode = document.querySelector('.pmc-layout__citation');
        if (pmcDetailPageNode && !document.querySelector('.journal-info-addon-detail') && !document.querySelector('.journal-info-placeholder-detail')) {
            const placeholderDiv = document.createElement('div');
            placeholderDiv.className = 'journal-info-placeholder-detail';
            placeholderDiv.style.marginTop = '10px';
            placeholderDiv.style.marginBottom = '10px';
            placeholderDiv.innerHTML = loadingHTML;
            pmcDetailPageNode.parentNode.insertBefore(placeholderDiv, pmcDetailPageNode.nextSibling);
        }
    }

    function processGoogleScholarResults(jcrData) {
        if (isGSProcessing) return;
        isGSProcessing = true;

        const modalBg = document.querySelector('#gs_md_s');
        const modal = document.querySelector('#gs_cit');
        const modalBgDisplay = modalBg ? modalBg.style.display : '';
        const modalDisplay = modal ? modal.style.display : '';
        if (modalBg) modalBg.style.display = 'none';
        if (modal) modal.style.display = 'none';

        const results = document.querySelectorAll('#gs_res_ccl_mid .gs_r');
        const observerTarget = document.querySelector('#gs_cit-bdy');

        let onCitationLoadedCallback = null;

        const observer = new MutationObserver(() => {
            if (!onCitationLoadedCallback) return;

            const citation = document.querySelector('#gs_citt');
            if (!citation || !citation.querySelector('.gs_citr')) return;

            let text = citation.querySelector('.gs_citr')?.textContent || '';
            const callbackToRun = onCitationLoadedCallback;
            onCitationLoadedCallback = null;
            callbackToRun(text);
            document.body.click();
        });

        if (observerTarget) {
            observer.observe(observerTarget, { childList: true, subtree: true });
        }

        function processItem(index) {
            if (index >= results.length) {
                if (modalBg) modalBg.style.display = modalBgDisplay;
                if (modal) modal.style.display = modalDisplay;
                observer.disconnect();
                isGSProcessing = false;
                return;
            }

            const result = results[index];
            const btn = result.querySelector('.gs_or_cit');

            if (result.querySelector('.journal-info-addon')) {
                processItem(index + 1);
                return;
            }

            const gsA = result.querySelector('.gs_a');
            if (gsA && !result.querySelector('.journal-info-placeholder')) {
                const placeholderDiv = document.createElement('div');
                placeholderDiv.className = 'journal-info-placeholder';
                placeholderDiv.style.marginTop = '5px';
                placeholderDiv.innerHTML = `<span style="background-color:#f0f0f0;color:#999;padding:2px 3px;border-radius:3px;">Loading Data...</span>`;
                gsA.insertAdjacentElement('afterend', placeholderDiv);
            }

            if (btn) {
                let timeout = setTimeout(() => {
                    console.log('Timeout waiting for citation popup. Skipping item.');
                    const placeholder = result.querySelector('.journal-info-placeholder');
                    if (placeholder) placeholder.remove();
                    processItem(index + 1);
                }, 2000);

                const insertionCallback = (citationText) => {
                    clearTimeout(timeout);
                    let match = citationText.match(/\[J\]\.\s*(.+?),\s*\d{4}/);
                    const placeholder = result.querySelector('.journal-info-placeholder');

                    if (match) {
                        let journalName = match[1].trim();
                        const jcrEntry = findJournalEntry(journalName, jcrData);
                        const infoHtml = generateInfoHTML(jcrEntry);

                        if (infoHtml && placeholder) {
                            placeholder.className = 'journal-info-addon';
                            placeholder.innerHTML = infoHtml;
                        } else if (infoHtml) {
                            const infoDiv = document.createElement('div');
                            infoDiv.className = 'journal-info-addon';
                            infoDiv.style.marginTop = '5px';
                            infoDiv.innerHTML = infoHtml;
                            if (gsA) gsA.insertAdjacentElement('afterend', infoDiv);
                        } else if (placeholder) {
                            placeholder.remove();
                        }
                    } else if (placeholder) {
                        placeholder.remove();
                    }
                    
                    setTimeout(() => {
                        processItem(index + 1);
                    }, 250);
                };

                onCitationLoadedCallback = insertionCallback;
                const href = btn.getAttribute('href');
                if (href && href.toLowerCase().startsWith('javascript:')) {
                    btn.removeAttribute('href');
                    btn.click();
                    btn.setAttribute('href', href);
                } else {
                    btn.click();
                }

            } else {
                const placeholder = result.querySelector('.journal-info-placeholder');
                if (placeholder) placeholder.remove();
                processItem(index + 1);
            }
        }
        processItem(0);
    }

    function main(jcrData) {
        jcrData.forEach(row => {
            row._wordSet = row.name_set ? new Set(row.name_set.split(',')) : new Set();
        });

        if (window.location.hostname.includes('scholar.google')) {
            const runGSProcessing = () => processGoogleScholarResults(jcrData);
            runGSProcessing();

            const observer = new MutationObserver(mutations => {
                for (const mutation of mutations) {
                    if (mutation.addedNodes.length) {
                        runGSProcessing();
                        break;
                    }
                }
            });
            const targetNode = document.getElementById('gs_res_ccl');
            if (targetNode) {
                observer.observe(targetNode, { childList: true, subtree: true });
            }
            return;
        }

        function processSearchResults() {
            document.querySelectorAll('article.full-docsum').forEach(article => {
                if (article.querySelector('.journal-info-addon')) return;

                const citationElement = article.querySelector('.docsum-journal-citation');
                if (!citationElement) return;

                const journalNameText = citationElement.textContent.split('.')[0].replace(/\([^)]*\)/g, '').trim();
                const jcrEntry = findJournalEntry(journalNameText, jcrData);
                const infoHtml = generateInfoHTML(jcrEntry);

                if (infoHtml) {
                    const placeholder = article.querySelector('.journal-info-placeholder');
                    if (placeholder) {
                        placeholder.className = 'journal-info-addon';
                        placeholder.innerHTML = infoHtml;
                    } else {
                        const infoDiv = document.createElement('div');
                        infoDiv.className = 'journal-info-addon';
                        infoDiv.style.marginTop = '5px';
                        infoDiv.innerHTML = infoHtml;
                        citationElement.parentNode.insertBefore(infoDiv, citationElement.nextSibling);
                    }
                }
            });
            applyFilters();
        }

        function processDetailPage() {
            const articleSource = document.querySelector('.article-source');
            const citationElement = document.querySelector('.citation-journal');

            if (!articleSource || !citationElement || document.querySelector('.journal-info-addon-detail')) {
                return;
            }

            const journalNameText = citationElement.textContent.split('.')[0].replace(/\([^)]*\)/g, '').trim();
            const jcrEntry = findJournalEntry(journalNameText, jcrData);
            const infoHtml = generateInfoHTML(jcrEntry);

            if (infoHtml) {
                const placeholder = document.querySelector('.journal-info-placeholder-detail');
                if (placeholder) {
                    placeholder.className = 'journal-info-addon-detail';
                    placeholder.innerHTML = infoHtml;
                } else {
                    const infoDiv = document.createElement('div');
                    infoDiv.className = 'journal-info-addon-detail';
                    infoDiv.style.marginTop = '10px';
                    infoDiv.style.marginBottom = '10px';
                    infoDiv.innerHTML = infoHtml;
                    articleSource.parentNode.insertBefore(infoDiv, articleSource.nextSibling);
                }
            }
        }

        function processPMCDetailPage() {
            const citationElement = document.querySelector('.pmc-layout__citation');
            if (!citationElement || document.querySelector('.journal-info-addon-detail')) {
                return;
            }

            const journalNameElement = citationElement.querySelector('button');
            if (!journalNameElement) return;

            const journalNameText = journalNameElement.textContent.trim();
            const jcrEntry = findJournalEntry(journalNameText, jcrData);
            const infoHtml = generateInfoHTML(jcrEntry);

            if (infoHtml) {
                const placeholder = document.querySelector('.journal-info-placeholder-detail');
                if (placeholder) {
                    placeholder.className = 'journal-info-addon-detail';
                    placeholder.innerHTML = infoHtml;
                } else {
                    const infoDiv = document.createElement('div');
                    infoDiv.className = 'journal-info-addon-detail';
                    infoDiv.style.marginTop = '10px';
                    infoDiv.style.marginBottom = '10px';
                    infoDiv.innerHTML = infoHtml;
                    citationElement.parentNode.insertBefore(infoDiv, citationElement.nextSibling);
                }
            }
        }

        const searchResultsNode = document.getElementById('search-results');
        const pubmedDetailPageNode = document.querySelector('.full-view .article-source');
        const pmcDetailPageNode = document.querySelector('.pmc-layout__citation');

        if (searchResultsNode) {
            createFilters();
            processSearchResults();

            const observer = new MutationObserver(mutations => {
                for (const mutation of mutations) {
                    if (mutation.addedNodes.length) {
                        processSearchResults();
                        break;
                    }
                }
            });
            observer.observe(searchResultsNode, { childList: true, subtree: true });

        } else if (pubmedDetailPageNode) {
            const runDetailProcessing = () => processDetailPage();
            runDetailProcessing();

            const observer = new MutationObserver(runDetailProcessing);
            const targetNode = document.getElementById('main-content');
            if (targetNode) {
                observer.observe(targetNode, { childList: true, subtree: true });
            }
        } else if (pmcDetailPageNode) {
            const runPMCDetailProcessing = () => processPMCDetailPage();
            runPMCDetailProcessing();

            const observer = new MutationObserver(runPMCDetailProcessing);
            const targetNode = document.getElementById('main-content');
            if (targetNode) {
                observer.observe(targetNode, { childList: true, subtree: true });
            }
        }
    }

    function injectStyles() {
        const style = document.createElement('style');
        style.textContent = `
        .noUi-horizontal .noUi-handle {
            right: 0px;
        }
    `;
        document.head.appendChild(style);
    }


    async function initialize() {
        injectStyles();
        insertLoadingPlaceholders();

        let { customKey } = await new Promise(resolve => chrome.storage.sync.get({ customKey: 'general' }, resolve));
        let jcrData = [];
        let loadSuccess = false;

        // Attempt to load with the custom key first, unless it's already 'general'
        if (customKey && customKey !== 'general') {
            try {
                let SECRET_KEY = await fetchAndCache(`${SERVER_URL}/data/${customKey}_key`, `cached_${customKey}`);
                SECRET_KEY = SECRET_KEY.trim();
                
                if (SECRET_KEY.includes("VIP")) {
                    const data = await loadData(SECRET_KEY, customKey);
                    if (data.length > 0) {
                        jcrData = data;
                        loadSuccess = true;
                        
                        const settings = await new Promise(resolve => chrome.storage.sync.get({ enhanceMode: true }, resolve));
                        enhance_mode = settings.enhanceMode;
                        chrome.storage.sync.set({ 'isVIP': true });
                    }
                }
            } catch (error) {
                console.warn(`Failed to load data with custom key "${customKey}". Falling back to general mode.`, error);
            }
        }

        // If loading with custom key failed or was skipped, load with general key
        if (!loadSuccess) {
            if (customKey !== 'general') {
                console.log("Falling back to general mode.");
                // Update storage to reflect the fallback. This is important for the popup UI.
                chrome.storage.sync.set({
                    'isVIP': false,
                    'enhanceMode': false,
                    'customKey': 'general'
                });
            }
            
            try {
                customKey = 'general';
                let SECRET_KEY = await fetchAndCache(`${SERVER_URL}/data/general_key`, 'cached_general');
                SECRET_KEY = SECRET_KEY.trim();
                jcrData = await loadData(SECRET_KEY, 'general');
                enhance_mode = false; // General mode is never enhanced
            } catch (error) {
                console.error("Failed to load data with general key.", error);
            }
        }

        // Run main logic if any data was loaded
        if (jcrData && jcrData.length > 0) {
            main(jcrData);
        } else {
            console.error("Failed to load any JCR data. Scholarship features will be disabled.");
        }
    }

    window.addEventListener('load', initialize);
})();